struct CaseStudyListDynamic: View {
    private static let initialItemCount = 40
    @State private var items: [Item] = (1...Self.initialItemCount).map { i in
        Item(id: "Item \(i)")
    }
    @State private var nextID: Int = Self.initialItemCount + 1
    var body: some View {
        List {
            ForEach(items) { item in
                LifecycleMonitor(label: item.id)
            }
            .onDelete { offsets in
                items.remove(atOffsets: offsets)
            }
        }
        .safeAreaInset(edge: .bottom) {
            Text("`List` recycles views during scrolling, so `onAppear` gets called often. But `List` preserves the state for all list items.")
                .font(.callout)
                .padding()
                .frame(maxWidth: .infinity, alignment: .leading)
                .background(.regularMaterial)
        }
        .toolbar {
            ToolbarItem {
                Button("Prepend") {
                    let newItem = Item(id: "Item \(nextID)")
                    nextID += 1
                    items.insert(newItem, at: 0)
                }
            }
            ToolbarItem {
                Button("Append") {
                    let newItem = Item(id: "Item \(nextID)")
                    nextID += 1
                    items.append(newItem)
                }
            }
        }
        .animation(.default, value: items)
        .navigationTitle("Dynamic List")
    }
}

struct CaseStudyNavigationStack: View {
    @State private var navigationPath: [Int] = []
    var body: some View {
        NavigationStack(path: $navigationPath) {
            Content(level: 1)
                .navigationDestination(for: Int.self) { level in
                    Content(level: level)
                }
        }
    }
    struct Content: View {
        var level: Int
        var body: some View {
            List {
                Section {
                    NavigationLink(value: level + 1) {
                        LifecycleMonitor(label: "Level \(level)")
                    }
                } footer: {
                    if level == 1 {
                        Text("Navigation views keep the state of content views on the navigation stack alive. `onAppear` and `onDisappear` get called as you navigate. Popping a view off the stack ends the view's lifetime, destroying its state.")
                            .font(.callout)
                            .frame(maxWidth: .infinity, alignment: .leading)
                    }
                }
            }
            .listStyle(.plain)
            .navigationTitle(level == 1 ? "NavigationStack" : "Level \(level)")
        }
    }
}
